1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single live cell (underpopulation)", () => {
10	    const liveCells: Cell[] = [[0, 0]];
11	    const result = nextGeneration(liveCells);
12	    expect(result).toEqual([]);
13	  });
14	  it("should kill two adjacent live cells (underpopulation)", () => {
15	    const liveCells: Cell[] = [[0, 0], [1, 0]];
16	    const result = nextGeneration(liveCells);
17	    expect(result).toEqual([]);
18	  });
19	  it("should keep a block pattern unchanged (still life)", () => {
20	    const liveCells: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
21	    const result = nextGeneration(liveCells);
22	    expect(result).toEqual(
23	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]])
24	    );
25	    expect(result).toHaveLength(4);
26	  });
27	  it.todo("should oscillate a blinker from vertical to horizontal");
28	  it.todo("should handle cells with negative coordinates");
29	});
30

1	export type Cell = [number, number];
2	
3	export function nextGeneration(liveCells: Cell[]): Cell[] {
4	  const alive = new Set(liveCells.map(([x, y]) => `${x},${y}`));
5	  const neighborCounts = new Map<string, number>();
6	
7	  for (const [x, y] of liveCells) {
8	    for (let dx = -1; dx <= 1; dx++) {
9	      for (let dy = -1; dy <= 1; dy++) {
10	        if (dx === 0 && dy === 0) continue;
11	        const key = `${x + dx},${y + dy}`;
12	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
13	      }
14	    }
15	  }
16	
17	  const result: Cell[] = [];
18	  for (const [key, count] of neighborCounts) {
19	    if (count === 3 || (alive.has(key) && count === 2)) {
20	      const [x, y] = key.split(",").map(Number);
21	      result.push([x, y]);
22	    }
23	  }
24	
25	  return result;
26	}
